/**
 * src/services/vaultMarketReport.ts
 * VAULT Market Report Service — V3-27
 *
 * Generates and retrieves weekly material market reports.
 * Reports are auto-generated by SCOUT every Monday and stored in Supabase.
 * In V3 external, reports are mocked. On V2 integration, replace
 * `_mockReportCache` with Supabase reads/writes.
 *
 * Public API:
 *   getLatestMarketReport()         → Promise<MarketReport | null>
 *   generateWeeklyMarketReport()    → Promise<MarketReport>
 *   hasNewReport()                  → boolean
 *   markReportSeen()                → void
 *
 * Supabase table required (V2 integration):
 *   `material_market_reports` — id, week_label, generated_at, report_data (JSONB),
 *                               is_seen (boolean), user_id
 */

import { syncToSupabase, fetchFromSupabase } from './supabaseService';

// ─── Types ─────────────────────────────────────────────────────────────────────

export interface MarketReportItem {
  item_name: string;
  display_name: string;
  vault_price: number;
  market_best: number;
  market_best_supplier: string;
  unit: string;
  diff_pct: number;           // positive = vault above market, negative = vault below
  direction: 'up' | 'down' | 'stable'; // price trend since last week
  weekly_change_pct: number;  // market price change vs prior week
  potential_savings_per_unit: number;
  status: 'green' | 'yellow' | 'red'; // competitiveness status
  recommendation: string;
}

export interface MarketReportTopMover {
  item_name: string;
  display_name: string;
  supplier_name: string;
  change_pct: number;
  direction: 'up' | 'down';
  current_price: number;
  previous_price: number;
  unit: string;
  severity: 'info' | 'warning' | 'critical';
}

export interface MarketReport {
  id: string;
  week_label: string;           // e.g. "Mar 30 – Apr 5, 2026"
  generated_at: string;         // ISO timestamp (Monday ~6:00 AM)
  items_tracked: number;
  avg_savings_pct: number;      // avg % VAULT is above market across all items
  total_potential_savings: number; // total $ if all items moved to market best
  items_at_risk: number;        // items where vault_price > 25% above market
  items_competitive: number;    // items where vault_price ≤ 10% of market
  top_movers: MarketReportTopMover[];
  savings_opportunities: MarketReportItem[];
  summary: string;
  is_new: boolean;              // true until user views report
}

