// Tracks whether the current user has seen the latest report
let _reportSeen = false;

// ─── Public API ────────────────────────────────────────────────────────────────

/**
 * Returns the latest market report.
 * V2 integration: replace with `fetchFromSupabase('material_market_reports', ...)`
 */
export async function getLatestMarketReport(): Promise<MarketReport | null> {
  // STUB — wire to Supabase on V2 integration
  // const rows = await fetchFromSupabase('material_market_reports', { order: 'generated_at.desc', limit: 1 });
  // return rows?.[0] ?? null;

  return { ..._mockReport, is_new: !_reportSeen };
}

/**
 * Auto-generates a fresh weekly market report.
 * Called every Monday by SCOUT. In production, this runs as a Supabase
 * scheduled function or n8n workflow. In V3 external, returns mock data.
 *
 * V2 integration: replace body with real Supabase write +
 * SCOUT agent scan across all tracked items.
 */
export async function generateWeeklyMarketReport(): Promise<MarketReport> {
  const now = new Date().toISOString();

  // STUB — production would: scan all SCOUT-tracked items, compare vs VAULT prices,
  // compute top movers, persist to Supabase, then trigger notification.
  await syncToSupabase({
    table: 'material_market_reports',
    data: {
      id: _mockReport.id,
      week_label: _mockReport.week_label,
      generated_at: now,
      report_data: _mockReport,
      is_seen: false,
    },
    operation: 'upsert',
  });

  _reportSeen = false;
  return { ..._mockReport, generated_at: now, is_new: true };
}

/**
 * Returns true if a new (unseen) market report is available.
 * Used to show the notification badge on the sidebar.
 */
export function hasNewReport(): boolean {
  return !_reportSeen;
}

/**
 * Marks the current report as seen.
 * Call when the user navigates to Material Intelligence or opens the report.
 * V2 integration: `syncToSupabase('material_market_reports', { is_seen: true })`
 */
export function markReportSeen(): void {
  _reportSeen = true;
}
